starterCode.javascript:
const express = require('express');
const app = express();
app.get('/?', (req, res) => {
  if (req.query.admin) {
    res.status(200).send('Hello, World!');
  } else {
    res.status(401).send();
  }
});
app.use(express.json());
app.all('*', (req, res) => {
  res.status(405).send();
});
const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});

